package quota

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
)

// MockResource implements resource.Resource for testing
type mockResource struct {
	events chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func newMockResource() *mockResource {
	return &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 100),
	}
}

func (m *mockResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.events
}

func (m *mockResource) Store(context.Context) (resource.Store[*cilium_v2.CiliumNetworkPolicy], error) {
	return nil, nil
}

func (m *mockResource) Observe(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.Events(ctx, opts...)
}

// TestPolicyQuotaController_CheckQuota tests the quota enforcement
func TestPolicyQuotaController_CheckQuota(t *testing.T) {
	logger := logrus.New().WithField("test", "checkquota")
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(logger, mockRes, 3)

	// Initially, quota should be available
	assert.NoError(t, controller.CheckQuota("default"))

	// Simulate adding policies
	policy1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "default",
			Name:      "policy1",
		},
	}

	policy2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "default",
			Name:      "policy2",
		},
	}

	policy3 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "default",
			Name:      "policy3",
		},
	}

	// Add policies
	assert.NoError(t, controller.onUpsert(policy1))
	assert.Equal(t, 1, controller.GetNamespaceCount("default"))

	assert.NoError(t, controller.onUpsert(policy2))
	assert.Equal(t, 2, controller.GetNamespaceCount("default"))

	assert.NoError(t, controller.onUpsert(policy3))
	assert.Equal(t, 3, controller.GetNamespaceCount("default"))

	// Now quota should be exceeded
	assert.Error(t, controller.CheckQuota("default"))
	assert.Contains(t, controller.CheckQuota("default").Error(), "policy quota exceeded")

	// Delete one policy
	assert.NoError(t, controller.onDelete(policy1))
	assert.Equal(t, 2, controller.GetNamespaceCount("default"))

	// Quota should be available again
	assert.NoError(t, controller.CheckQuota("default"))
}

// TestPolicyQuotaController_MultipleNamespaces tests quota enforcement across namespaces
func TestPolicyQuotaController_MultipleNamespaces(t *testing.T) {
	logger := logrus.New().WithField("test", "multinamespace")
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(logger, mockRes, 2)

	// Create policies in different namespaces
	policy1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "ns1",
			Name:      "policy1",
		},
	}

	policy2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "ns2",
			Name:      "policy1",
		},
	}

	// Add policies to different namespaces
	assert.NoError(t, controller.onUpsert(policy1))
	assert.NoError(t, controller.onUpsert(policy2))

	// Both namespaces should be independent
	assert.Equal(t, 1, controller.GetNamespaceCount("ns1"))
	assert.Equal(t, 1, controller.GetNamespaceCount("ns2"))
	assert.NoError(t, controller.CheckQuota("ns1"))
	assert.NoError(t, controller.CheckQuota("ns2"))

	// Add more policies to ns1 to exceed quota
	policy3 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "ns1",
			Name:      "policy2",
		},
	}

	policy4 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "ns1",
			Name:      "policy3",
		},
	}

	assert.NoError(t, controller.onUpsert(policy3))
	assert.NoError(t, controller.onUpsert(policy4))

	// ns1 should exceed quota
	assert.Equal(t, 3, controller.GetNamespaceCount("ns1"))
	assert.Error(t, controller.CheckQuota("ns1"))

	// ns2 should still have available quota
	assert.NoError(t, controller.CheckQuota("ns2"))
}

// TestPolicyQuotaController_ClusterScoped tests that cluster-scoped policies are ignored
func TestPolicyQuotaController_ClusterScoped(t *testing.T) {
	logger := logrus.New().WithField("test", "clusterscoped")
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(logger, mockRes, 1)

	// Create a cluster-scoped policy (no namespace)
	clusterPolicy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "",
			Name:      "cluster-policy",
		},
	}

	// Add cluster-scoped policy
	assert.NoError(t, controller.onUpsert(clusterPolicy))

	// Cluster-scoped policies should not affect quota
	assert.Equal(t, 0, controller.GetNamespaceCount(""))

	// Quota check for empty namespace should succeed
	assert.NoError(t, controller.CheckQuota(""))
}

// TestPolicyQuotaController_Run tests the controller's Run loop
func TestPolicyQuotaController_Run(t *testing.T) {
	logger := logrus.New().WithField("test", "run")
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(logger, mockRes, 2)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Start controller in a goroutine
	go func() {
		err := controller.Run(ctx)
		if err != nil && err != context.Canceled {
			t.Logf("controller run error: %v", err)
		}
	}()

	// Send a Sync event first to indicate initial sync
	syncEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Sync,
	}
	syncEvent.done = make(chan error, 1)
	mockRes.events <- syncEvent

	// Wait for sync to be processed
	<-syncEvent.done

	// Send an Upsert event
	policy1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "default",
			Name:      "policy1",
		},
	}

	upsertEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Object: policy1,
	}
	upsertEvent.done = make(chan error, 1)
	mockRes.events <- upsertEvent

	// Wait for event to be processed
	err := <-upsertEvent.done
	assert.NoError(t, err)
	assert.Equal(t, 1, controller.GetNamespaceCount("default"))

	// Send a Delete event
	deleteEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Delete,
		Object: policy1,
	}
	deleteEvent.done = make(chan error, 1)
	mockRes.events <- deleteEvent

	// Wait for event to be processed
	err = <-deleteEvent.done
	assert.NoError(t, err)
	assert.Equal(t, 0, controller.GetNamespaceCount("default"))

	// Cancel context to stop the controller
	cancel()
}

// TestPolicyQuotaController_ZeroQuota tests behavior with zero quota
func TestPolicyQuotaController_ZeroQuota(t *testing.T) {
	logger := logrus.New().WithField("test", "zeroquota")
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(logger, mockRes, 0)

	// With zero quota, even the first policy should exceed quota
	assert.Error(t, controller.CheckQuota("default"))

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "default",
			Name:      "policy1",
		},
	}

	assert.NoError(t, controller.onUpsert(policy))
	assert.Equal(t, 1, controller.GetNamespaceCount("default"))
	assert.Error(t, controller.CheckQuota("default"))
}

// TestPolicyQuotaController_HighQuota tests behavior with a high quota
func TestPolicyQuotaController_HighQuota(t *testing.T) {
	logger := logrus.New().WithField("test", "highquota")
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(logger, mockRes, 1000)

	// Add many policies
	for i := 0; i < 999; i++ {
		policy := &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Namespace: "default",
				Name:      "policy" + string(rune(i)),
			},
		}
		assert.NoError(t, controller.onUpsert(policy))
	}

	// Should have room for one more
	assert.NoError(t, controller.CheckQuota("default"))

	// Add one more
	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: "default",
			Name:      "policy999",
		},
	}
	assert.NoError(t, controller.onUpsert(policy))

	// Now quota should be exceeded
	assert.Error(t, controller.CheckQuota("default"))
}

