)

var log = logrus.NewEntry(logrus.New()).WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	logger                logrus.FieldLogger
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPerNamespace       int

	// mu protects the counters map
	mu       sync.RWMutex
	counters map[string]int // namespace -> count of CiliumNetworkPolicy
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	logger logrus.FieldLogger,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	if logger == nil {
		logger = log
	}
	return &PolicyQuotaController{
		logger:                logger,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		maxPerNamespace:       maxPerNamespace,
		counters:              make(map[string]int),
	}
}

// Run implements the controller loop that watches CiliumNetworkPolicy resources
// and maintains per-namespace counts.
func (c *PolicyQuotaController) Run(ctx context.Context) error {
	events := c.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case event, ok := <-events:
			if !ok {
				return nil
			}

			var err error
			switch event.Kind {
			case resource.Upsert:
				err = c.onUpsert(event.Object)
			case resource.Delete:
				err = c.onDelete(event.Object)
			case resource.Sync:
				// Sync event indicates the controller has synchronized with the API server
				event.Done(nil)
				continue
			}

			event.Done(err)
		}
	}
}

// onUpsert handles upsert events for CiliumNetworkPolicy resources.
func (c *PolicyQuotaController) onUpsert(policy *cilium_v2.CiliumNetworkPolicy) error {
	namespace := policy.ObjectMeta.Namespace
	if namespace == "" {
		// Skip cluster-scoped resources
		return nil
	}

	c.mu.Lock()
	defer c.mu.Unlock()

	c.counters[namespace]++
	c.logger.WithFields(logrus.Fields{
		"namespace": namespace,
		"count":     c.counters[namespace],
	}).Debugf("Incremented policy count for namespace")

	return nil
}

// onDelete handles delete events for CiliumNetworkPolicy resources.
func (c *PolicyQuotaController) onDelete(policy *cilium_v2.CiliumNetworkPolicy) error {
	namespace := policy.ObjectMeta.Namespace
	if namespace == "" {
		// Skip cluster-scoped resources
		return nil
	}

	c.mu.Lock()
	defer c.mu.Unlock()

	if c.counters[namespace] > 0 {
		c.counters[namespace]--
	}

	c.logger.WithFields(logrus.Fields{
		"namespace": namespace,
		"count":     c.counters[namespace],
	}).Debugf("Decremented policy count for namespace")

	return nil
}

// CheckQuota checks if a new policy can be added to the given namespace
// without exceeding the quota. Returns an error if quota would be exceeded.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	if namespace == "" {
		// Skip quota check for cluster-scoped resources
		return nil
	}

	c.mu.RLock()
	defer c.mu.RUnlock()

	currentCount := c.counters[namespace]
	if currentCount >= c.maxPerNamespace {
		return fmt.Errorf(
			"policy quota exceeded for namespace %q: current count %d >= max %d",
			namespace,
			currentCount,
			c.maxPerNamespace,
		)
	}

	return nil
}

// GetNamespaceCount returns the current number of CiliumNetworkPolicy resources
// in the given namespace.
func (c *PolicyQuotaController) GetNamespaceCount(namespace string) int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.counters[namespace]
}

